const STORE_KEY = 'marineTrainingPlatform.v1';
const PASS_LIMIT = 80;

const state = loadState();
const $ = (sel, root = document) => root.querySelector(sel);
const $$ = (sel, root = document) => Array.from(root.querySelectorAll(sel));

function loadState() {
  try {
    return Object.assign({ completed: [], lastVisited: null, quizResults: {}, theme: 'light' }, JSON.parse(localStorage.getItem(STORE_KEY) || '{}'));
  } catch (_) {
    return { completed: [], lastVisited: null, quizResults: {}, theme: 'light' };
  }
}
function saveState() { localStorage.setItem(STORE_KEY, JSON.stringify(state)); }
function chapterById(id) { return PLATFORM.chapters.find(ch => ch.chapter === String(id).padStart(2, '0')); }
function quizById(id) { return PLATFORM.quizzes.find(q => q.chapter === String(id).padStart(2, '0')); }
function normalize(value) { return (value || '').toLowerCase().normalize('NFD').replace(/[\u0300-\u036f]/g, ''); }
function shuffle(items) {
  const copy = items.slice();
  for (let i = copy.length - 1; i > 0; i--) {
    const j = Math.floor(Math.random() * (i + 1));
    [copy[i], copy[j]] = [copy[j], copy[i]];
  }
  return copy;
}
function setView(name) {
  $$('.app-tabs button').forEach(btn => btn.classList.toggle('active', btn.dataset.view === name));
  $$('.view').forEach(view => view.classList.toggle('active-view', view.id === 'view-' + name));
  if (name === 'dashboard') renderDashboard();
}
function openChapter(id) {
  const chapter = chapterById(id);
  if (!chapter) return;
  state.lastVisited = chapter.chapter;
  saveState();
  setView('chapters');
  $$('.chapter-card').forEach(card => card.classList.toggle('active-chapter', card.dataset.chapter === chapter.chapter));
  $$('.chapter-link').forEach(btn => btn.classList.toggle('active', btn.dataset.chapter === chapter.chapter));
  const article = $('#chapter-' + chapter.chapter);
  if (article) article.scrollIntoView({ behavior: 'smooth', block: 'start' });
  updateProgressUI();
}
function nextRecommended() {
  return PLATFORM.chapters.find(ch => !state.completed.includes(ch.chapter)) || PLATFORM.chapters[0];
}
function toggleComplete(id, force) {
  const chapter = String(id).padStart(2, '0');
  const has = state.completed.includes(chapter);
  const should = typeof force === 'boolean' ? force : !has;
  if (should && !has) state.completed.push(chapter);
  if (!should && has) state.completed = state.completed.filter(x => x !== chapter);
  saveState();
  updateProgressUI();
  renderDashboard();
}
function updateProgressUI() {
  const total = PLATFORM.chapters.length;
  const completed = state.completed.length;
  const pct = Math.round((completed / total) * 100);
  document.documentElement.dataset.theme = state.theme || 'light';
  const themeBtn = $('#themeToggle');
  if (themeBtn) themeBtn.textContent = state.theme === 'dark' ? 'Lys modus' : 'Mørk modus';
  const bar = $('#progressBar'); if (bar) bar.style.width = pct + '%';
  const text = $('#progressText'); if (text) text.textContent = `${completed} av ${total} kapitler fullført (${pct}%).`;
  const completedCount = $('#completedCount'); if (completedCount) completedCount.textContent = completed;
  const last = $('#lastVisited'); if (last) last.textContent = state.lastVisited ? `Kap. ${state.lastVisited}` : 'Ingen';
  const avg = $('#quizAverage'); if (avg) avg.textContent = quizAverage() + '%';
  $$('.mark-complete').forEach(btn => {
    const done = state.completed.includes(btn.dataset.chapter);
    btn.classList.toggle('done', done);
    btn.textContent = done ? 'Fullført' : 'Marker fullført';
  });
  $$('.chapter-link').forEach(btn => btn.classList.toggle('done', state.completed.includes(btn.dataset.chapter)));
}
function quizAverage() {
  const values = Object.values(state.quizResults || {}).map(r => r.score || 0);
  if (!values.length) return 0;
  return Math.round(values.reduce((a,b) => a + b, 0) / values.length);
}
function renderDashboard() {
  updateProgressUI();
  const list = $('#dashboardChapterList');
  if (!list) return;
  list.innerHTML = PLATFORM.chapters.map(ch => {
    const done = state.completed.includes(ch.chapter);
    const q = state.quizResults[ch.chapter];
    return `<button class="status-card ${done ? 'done' : ''}" data-open-dashboard-chapter="${ch.chapter}"><strong>${ch.chapter}</strong><span>${escapeHtml(ch.shortTitle)}</span><em>${done ? 'Fullført' : 'Ikke fullført'}${q ? ' · Quiz ' + q.score + '%' : ''}</em></button>`;
  }).join('');
}
function initQuiz() {
  const select = $('#quizChapter');
  if (!select) return;
  select.innerHTML = PLATFORM.chapters.map(ch => `<option value="${ch.chapter}">${ch.chapter} ${escapeHtml(ch.shortTitle)}</option>`).join('');
  select.value = state.lastVisited || '01';
  select.addEventListener('change', () => renderQuiz(select.value));
  renderQuiz(select.value);
}
function renderQuiz(chapterId) {
  const quiz = quizById(chapterId);
  const root = $('#quizRoot');
  if (!root || !quiz) return;
  const prepared = shuffle(quiz.questions).map(q => {
    const choices = shuffle(q.choices.map((text, idx) => ({ text, original: idx })));
    return Object.assign({}, q, { choices, correctIndex: choices.findIndex(c => c.original === q.answer) });
  });
  root.dataset.chapter = quiz.chapter;
  root.quizData = prepared;
  root.innerHTML = `<div class="quiz-meta"><strong>${escapeHtml(quiz.title)}</strong><span>${prepared.length} spørsmål · bestått ved ${PASS_LIMIT}%</span></div>` + prepared.map((q, qi) => `
    <fieldset class="question" data-q="${qi}">
      <legend>${qi + 1}. ${escapeHtml(q.question)}</legend>
      ${q.choices.map((c, ci) => `<label><input type="radio" name="q${qi}" value="${ci}"><span>${escapeHtml(c.text)}</span></label>`).join('')}
      <p class="explanation hidden"></p>
    </fieldset>`).join('') + `<button id="submitQuiz">Lever quiz</button><div id="quizResult" class="quiz-result"></div>`;
  $('#submitQuiz').addEventListener('click', gradeQuiz);
  renderQuizHistory();
}
function gradeQuiz() {
  const root = $('#quizRoot');
  const data = root.quizData || [];
  let correct = 0;
  data.forEach((q, qi) => {
    const field = $(`.question[data-q="${qi}"]`, root);
    const selected = $(`input[name="q${qi}"]:checked`, root);
    const selectedIndex = selected ? Number(selected.value) : -1;
    const ok = selectedIndex === q.correctIndex;
    if (ok) correct++;
    field.classList.toggle('correct', ok);
    field.classList.toggle('wrong', !ok);
    const exp = $('.explanation', field);
    exp.classList.remove('hidden');
    exp.textContent = `${ok ? 'Riktig.' : 'Ikke helt.'} ${q.explanation}`;
  });
  const score = Math.round((correct / data.length) * 100);
  const passed = score >= PASS_LIMIT;
  const chapter = root.dataset.chapter;
  state.quizResults[chapter] = { score, passed, correct, total: data.length, date: new Date().toISOString() };
  if (passed) toggleComplete(chapter, true); else saveState();
  $('#quizResult').innerHTML = `<strong>${score}%</strong> · ${passed ? 'Bestått' : 'Ikke bestått'} · ${correct} av ${data.length} riktige.`;
  renderQuizHistory();
  updateProgressUI();
}
function renderQuizHistory() {
  const host = $('#quizHistory');
  if (!host) return;
  const rows = Object.entries(state.quizResults || {}).sort().map(([chapter, r]) => `<tr><td>Kap. ${chapter}</td><td>${r.score}%</td><td>${r.passed ? 'Bestått' : 'Ikke bestått'}</td><td>${new Date(r.date).toLocaleDateString('nb-NO')}</td></tr>`).join('');
  host.innerHTML = rows ? `<h3>Lagrede quizresultater</h3><table><thead><tr><th>Kapittel</th><th>Poengsum</th><th>Status</th><th>Dato</th></tr></thead><tbody>${rows}</tbody></table>` : '<p class="muted">Ingen quizresultater lagret ennå.</p>';
}
function renderQuickRefs() {
  const make = rows => `<table><thead><tr>${rows[0].map(h => `<th>${escapeHtml(h)}</th>`).join('')}</tr></thead><tbody>${rows.slice(1).map(row => `<tr>${row.map(c => `<td>${escapeHtml(c)}</td>`).join('')}</tr>`).join('')}</tbody></table>`;
  $('#partsTable').innerHTML = make([['Reservedel','System','Kontroller'], ...PLATFORM.quickrefs.parts]);
  $('#symptomsTable').innerHTML = make([['Symptom','Kontroller først','Fallgruve'], ...PLATFORM.quickrefs.symptoms]);
  $('#checksTable').innerHTML = make([['Kontroll','Innhold','Når'], ...PLATFORM.quickrefs.checks]);
}
function classifyQuery(query) {
  const q = normalize(query);
  const tags = [];
  if (/\b(cat|caterpillar|volvo|penta|cummins|mitsubishi|man|scania|yanmar)\b/.test(q)) tags.push('produsent');
  if (/\b(serial|serienummer|motornummer|engine number|esn|cpl|product number|arrangement)\b|[a-z]{1,4}\d{3,}/.test(q)) tags.push('serienummer/motornummer');
  if (/\b(filter|impeller|turbo|sensor|pumpe|reim|dynamo|starter|injektor|pakning|termostat|kjoler|gear)\b/.test(q)) tags.push('komponent/reservedel');
  if (/\b(feilkode|alarm|lav effekt|hoy temperatur|startproblem|oljetrykk|overoppheting|ujevn)\b|\bspn\b|\bfmi\b|\bp\d{4}\b/.test(q)) tags.push('feilkode/symptom');
  return tags.length ? tags : ['generelt søk'];
}
function scoreChapter(ch, query, type) {
  const q = normalize(query);
  if (!q) return 0;
  const hay = normalize(ch.title + ' ' + ch.text);
  const terms = q.split(/\s+/).filter(Boolean);
  let score = 0;
  terms.forEach(term => { if (hay.includes(term)) score += term.length > 3 ? 3 : 1; });
  const title = normalize(ch.title);
  terms.forEach(term => { if (title.includes(term)) score += 6; });
  const maker = PLATFORM.manufacturers.find(m => m.aliases.some(a => q.includes(normalize(a))));
  if (maker && ch.chapter === maker.chapter) score += 20;
  if (type === 'maker' && maker && ch.chapter === maker.chapter) score += 30;
  if (type === 'serial' && /serienummer|motornummer|esn|cpl|product number|arrangement|dataplate/.test(hay)) score += 5;
  if (type === 'component' && /komponent|pumpe|filter|sensor|turbo|impeller|reim|dynamo|starter|injektor/.test(hay)) score += 5;
  if (type === 'fault' && /feil|alarm|symptom|feilsoking|lav effekt|temperatur|startproblem/.test(hay)) score += 5;
  if (type === 'part' && /reservedel|part number|delnummer|servicekit|supersession/.test(hay)) score += 5;
  return score;
}
function renderSearch() {
  const input = $('#smartSearch');
  const type = $('#searchType');
  const results = $('#searchResults');
  const hints = $('#searchHints');
  function update() {
    const query = input.value.trim();
    const tags = classifyQuery(query);
    hints.innerHTML = tags.map(t => `<span>${escapeHtml(t)}</span>`).join('');
    if (!query) { results.innerHTML = '<p class="muted">Skriv inn søk etter for eksempel ESN, D4, impeller, lav effekt, SPN/FMI, sensor eller produsent.</p>'; return; }
    const ranked = PLATFORM.chapters.map(ch => ({ ch, score: scoreChapter(ch, query, type.value) })).filter(x => x.score > 0).sort((a,b) => b.score - a.score).slice(0, 12);
    results.innerHTML = ranked.length ? ranked.map(({ch, score}) => `<button class="search-result" data-search-chapter="${ch.chapter}"><strong>${ch.chapter} ${escapeHtml(ch.shortTitle)}</strong><span>Relevans ${score} · ${escapeHtml(ch.text.slice(0, 220))}...</span></button>`).join('') : '<p class="muted">Ingen treff. Prøv produsent, komponentnavn, serienummerbegrep eller symptom.</p>';
  }
  input.addEventListener('input', update);
  type.addEventListener('change', update);
  update();
}
function escapeHtml(s) { return String(s).replace(/[&<>'"]/g, c => ({'&':'&amp;','<':'&lt;','>':'&gt;',"'":'&#39;','"':'&quot;'}[c])); }
function safeOn(selector, eventName, handler, root = document) {
  const node = $(selector, root);
  if (node) node.addEventListener(eventName, handler);
  return node;
}
function bindCriticalActionRouter() {
  if (document.documentElement.dataset.criticalRouterBound === 'true') return;
  document.documentElement.dataset.criticalRouterBound = 'true';
  document.addEventListener('click', event => {
    const critical = event.target.closest('#startTrainerLesson,[data-trainer-level],#openFlashcards,#simStartDay,#simNextCase,#simContinueDaily');
    if (!critical) return;
    event.preventDefault();
    event.stopImmediatePropagation();
    try {
      if (critical.matches('#startTrainerLesson')) {
        setView('trainer');
        startSelectedTrainerLevel('Start leksjon-knappen');
        return;
      }
      if (critical.matches('[data-trainer-level]')) {
        setView('trainer');
        handleTrainerStart(Number(critical.dataset.trainerLevel), 'Learning Path');
        return;
      }
      if (critical.matches('#openFlashcards')) {
        setView('trainer');
        startTrainerFlashcards();
        return;
      }
      if (critical.matches('#simStartDay')) {
        setView('work-simulator');
        startSimDailyMission();
        return;
      }
      if (critical.matches('#simNextCase,#simContinueDaily')) {
        setView('work-simulator');
        continueSimCaseFlow();
      }
    } catch (error) {
      const message = `Handlingen kunne ikke startes: ${error?.message || error}`;
      if (critical.matches('#simStartDay,#simNextCase,#simContinueDaily') && $('#simResult')) $('#simResult').innerHTML = `<div class="sim-result warn"><h4>Teknisk feil</h4><p>${escapeHtml(message)}</p></div>`;
      else if ($('#trainerStatus')) setTrainerStatus(message, true);
      else console.error(message);
    }
  }, true);
}
function bindEvents() {
  $$('.app-tabs button').forEach(btn => btn.addEventListener('click', () => setView(btn.dataset.view)));
  $$('[data-view-jump]').forEach(btn => btn.addEventListener('click', () => setView(btn.dataset.viewJump)));
  $$('.chapter-link').forEach(btn => btn.addEventListener('click', () => openChapter(btn.dataset.chapter)));
  $$('.mark-complete').forEach(btn => btn.addEventListener('click', () => toggleComplete(btn.dataset.chapter)));
  $$('.open-chapter').forEach(btn => btn.addEventListener('click', () => openChapter(btn.dataset.chapter)));
  document.addEventListener('click', event => {
    const dash = event.target.closest('[data-open-dashboard-chapter]');
    if (dash) openChapter(dash.dataset.openDashboardChapter);
    const search = event.target.closest('[data-search-chapter]');
    if (search) openChapter(search.dataset.searchChapter);
    const opener = event.target.closest('.open-chapter[data-chapter]');
    if (opener) openChapter(opener.dataset.chapter);
    const maker = event.target.closest('[data-maker-target]');
    if (maker) document.getElementById('maker-' + maker.dataset.makerTarget)?.scrollIntoView({ behavior: 'smooth', block: 'start' });
  });
  safeOn('#continueBtn', 'click', () => openChapter(state.lastVisited || nextRecommended().chapter));
  safeOn('#recommendedBtn', 'click', () => openChapter(nextRecommended().chapter));
  safeOn('#resetProgress', 'click', () => {
    if (!confirm('Vil du starte progresjon og quizresultater på nytt?')) return;
    state.completed = []; state.lastVisited = null; state.quizResults = {}; saveState(); updateProgressUI(); renderDashboard(); renderQuizHistory();
  });
  safeOn('#themeToggle', 'click', () => { state.theme = state.theme === 'dark' ? 'light' : 'dark'; saveState(); updateProgressUI(); });
  safeOn('#chapterFilter', 'input', event => {
    const q = normalize(event.target.value);
    $$('.chapter-link').forEach(btn => btn.classList.toggle('hidden', q && !normalize(btn.textContent).includes(q)));
  });
}

