const WORK_KEY = 'marineTrainingWorkMode.v1';
let selectedDiagramChapter = null;
let deferredInstallPrompt = null;
let installUnavailableReason = 'Installasjonsprompt er ikke tilgjengelig ennå. Prøv igjen etter at siden er lastet ferdig, eller bruk nettleserens meny hvis den tilbyr installasjon.';

function loadWorkState() {
  try {
    return Object.assign({ customers: [], notes: '', favorites: [], todos: [], logs: [], history: [] }, JSON.parse(localStorage.getItem(WORK_KEY) || '{}'));
  } catch (_) {
    return { customers: [], notes: '', favorites: [], todos: [], logs: [], history: [] };
  }
}
const workState = loadWorkState();
function saveWorkState(action) {
  if (action) workState.history.unshift({ action, date: new Date().toISOString() });
  workState.history = workState.history.slice(0, 80);
  localStorage.setItem(WORK_KEY, JSON.stringify(workState));
}
function addHistory(action) { saveWorkState(action); renderWorkMode(); }

function initPwa() {
  if ('serviceWorker' in navigator) {
    navigator.serviceWorker.register('./service-worker.js').then(() => setSyncStatus('Offline-modus klar.')).catch(() => setSyncStatus('Service worker kunne ikke registreres.'));
    navigator.serviceWorker.addEventListener('message', event => {
      if (event.data && event.data.type === 'sync-complete') setSyncStatus('Synkronisering fullført lokalt.');
    });
  }
  window.addEventListener('beforeinstallprompt', event => {
    event.preventDefault();
    deferredInstallPrompt = event;
    installUnavailableReason = '';
    updateInstallButton();
  });
  window.addEventListener('appinstalled', () => {
    deferredInstallPrompt = null;
    updateInstallButton(true);
  });
  const install = $('#installApp');
  if (install) install.addEventListener('click', async () => {
    if (isPwaInstalled()) {
      updateInstallButton(true);
      return;
    }
    if (isIosDevice()) {
      showInstallModal('Installer på iPhone/iPad', 'Tap the Share button, then ‘Add to Home Screen’.');
      return;
    }
    if (!deferredInstallPrompt) {
      showInstallModal('Installasjon er ikke tilgjengelig', installUnavailableReasonForPlatform());
      return;
    }
    try {
      deferredInstallPrompt.prompt();
      const choice = await deferredInstallPrompt.userChoice;
      deferredInstallPrompt = null;
      if (choice.outcome === 'accepted') {
        showInstallModal('Installasjon startet', 'Følg nettleserens bekreftelse for å fullføre installasjonen.');
      } else {
        showInstallModal('Installasjon avbrutt', 'Du kan trykke Installer app igjen senere hvis nettleseren fortsatt tilbyr installasjon.');
      }
    } catch (_) {
      deferredInstallPrompt = null;
      showInstallModal('Installasjon feilet', 'Nettleseren kunne ikke åpne installasjonsprompten akkurat nå. Last siden på nytt og prøv igjen.');
    }
    updateInstallButton();
  });
  updateInstallButton();
}
function setSyncStatus(text) { const el = $('#syncStatus'); if (el) el.textContent = text; }
function isPwaInstalled() {
  return window.matchMedia?.('(display-mode: standalone)').matches || window.navigator.standalone === true;
}
function isIosDevice() {
  const ua = navigator.userAgent || '';
  return /iPad|iPhone|iPod/.test(ua) || (navigator.platform === 'MacIntel' && navigator.maxTouchPoints > 1);
}
function isAndroidChrome() {
  const ua = navigator.userAgent || '';
  return /Android/.test(ua) && /Chrome\//.test(ua) && !/EdgA|OPR|SamsungBrowser|Firefox/.test(ua);
}
function installUnavailableReasonForPlatform() {
  if (!('serviceWorker' in navigator)) return 'Denne nettleseren støtter ikke service worker, som kreves for PWA-installasjon.';
  if (location.protocol !== 'https:' && location.hostname !== 'localhost' && location.hostname !== '127.0.0.1') return 'PWA-installasjon krever HTTPS. Åpne siden via GitHub Pages eller en sikker HTTPS-adresse.';
  if (isAndroidChrome()) return 'Chrome på Android kan installere appen når nettleseren har validert manifest og service worker. Vent noen sekunder, last siden på nytt, eller åpne menyen i Chrome og velg Installer app hvis valget vises der.';
  return 'Denne nettleseren tilbyr ikke en automatisk installasjonsprompt for denne siden. Bruk nettleserens meny hvis den har et valg for å installere eller legge siden til på startskjermen.';
}
function updateInstallButton(installed = false) {
  const btn = $('#installApp');
  if (!btn) return;
  if (installed || isPwaInstalled()) {
    btn.classList.add('hidden');
    btn.disabled = true;
    btn.setAttribute('aria-hidden', 'true');
    btn.title = 'Appen er allerede installert.';
    return;
  }
  btn.classList.remove('hidden');
  btn.disabled = false;
  btn.removeAttribute('aria-hidden');
  btn.textContent = isIosDevice() ? 'Installer app' : 'Installer app';
  btn.title = deferredInstallPrompt ? 'Installer Marine Learning Platform på denne enheten.' : installUnavailableReasonForPlatform();
}
function showInstallModal(title, message) {
  let modal = $('#installModal');
  if (!modal) {
    modal = document.createElement('div');
    modal.id = 'installModal';
    modal.className = 'install-modal hidden';
    modal.innerHTML = `<div class="install-dialog" role="dialog" aria-modal="true" aria-labelledby="installModalTitle"><button class="install-close" type="button" aria-label="Lukk">x</button><h2 id="installModalTitle"></h2><p id="installModalText"></p><button id="installModalOk" type="button">OK</button></div>`;
    document.body.appendChild(modal);
    modal.addEventListener('click', event => { if (event.target === modal) hideInstallModal(); });
    $('.install-close', modal)?.addEventListener('click', hideInstallModal);
    $('#installModalOk', modal)?.addEventListener('click', hideInstallModal);
    document.addEventListener('keydown', event => { if (event.key === 'Escape') hideInstallModal(); });
  }
  $('#installModalTitle', modal).textContent = title;
  $('#installModalText', modal).textContent = message;
  modal.classList.remove('hidden');
  $('#installModalOk', modal)?.focus();
}
function hideInstallModal() {
  $('#installModal')?.classList.add('hidden');
}

function initInteractiveDiagrams() {
  $$('.hotspot').forEach(node => {
    node.addEventListener('click', () => {
      selectedDiagramChapter = node.dataset.chapter;
      const topic = node.dataset.topic;
      const chapter = chapterById(selectedDiagramChapter);
      const title = $('#diagramTitle');
      const text = $('#diagramText');
      if (title) title.textContent = topic;
      if (text) text.textContent = `${topic} er koblet til kapittel ${selectedDiagramChapter}: ${chapter ? chapter.shortTitle : 'ukjent kapittel'}.`;
    });
  });
  const open = $('#diagramOpen');
  if (open) open.addEventListener('click', () => openChapter(selectedDiagramChapter || '11'));
}

function initPartsDatabase() {
  const maker = $('#partsMaker');
  const input = $('#partsSearch');
  if (!maker || !input) return;
  const makers = [...new Set(PARTS_DATABASE.map(p => p.manufacturer))].sort();
  maker.innerHTML = '<option value="all">Alle produsenter</option>' + makers.map(m => `<option value="${escapeHtml(m)}">${escapeHtml(m)}</option>`).join('');
  input.addEventListener('input', renderPartsResults);
  maker.addEventListener('change', renderPartsResults);
  renderPartsResults();
}
function partScore(part, query) {
  if (!query) return 1;
  const q = normalize(query);
  const hay = normalize([part.manufacturer, part.motor, part.serialNumberPattern, part.engineNumberPattern, part.component, part.system, part.category, part.partNumber, part.notes].join(' '));
  let score = 0;
  q.split(/\s+/).filter(Boolean).forEach(term => { if (hay.includes(term)) score += term.length > 3 ? 4 : 1; });
  if (normalize(part.partNumber) === q) score += 30;
  if (normalize(part.component).includes(q)) score += 15;
  if (normalize(part.motor).includes(q)) score += 10;
  return score;
}
function renderPartsResults() {
  const input = $('#partsSearch'); const maker = $('#partsMaker'); const host = $('#partsResults'); const stats = $('#partsStats');
  if (!input || !maker || !host) return;
  const query = input.value.trim();
  const filtered = PARTS_DATABASE.map(p => ({ p, score: partScore(p, query) }))
    .filter(x => (maker.value === 'all' || x.p.manufacturer === maker.value) && x.score > 0)
    .sort((a,b) => b.score - a.score || a.p.manufacturer.localeCompare(b.p.manufacturer))
    .slice(0, 80);
  if (stats) stats.innerHTML = `<span>${PARTS_DATABASE.length} poster</span><span>${filtered.length} treff vist</span><span>Verifisering kreves</span>`;
  host.innerHTML = filtered.map(({p}) => `<article class="part-result"><div><strong>${escapeHtml(p.partNumber)}</strong><span>${escapeHtml(p.manufacturer)} · ${escapeHtml(p.motor)} · ${escapeHtml(p.component)}</span></div><dl><dt>Serienummer</dt><dd>${escapeHtml(p.serialNumberPattern)}</dd><dt>Motornummer</dt><dd>${escapeHtml(p.engineNumberPattern)}</dd><dt>System</dt><dd>${escapeHtml(p.system)}</dd><dt>Kilde</dt><dd>${escapeHtml(p.documentation)}</dd></dl><p>${escapeHtml(p.notes)}</p><button class="open-chapter" data-chapter="${p.relatedChapter}">Åpne kapittel ${p.relatedChapter}</button><button class="secondary add-part-favorite" data-part="${escapeHtml(p.partNumber)}">Favoritt</button></article>`).join('') || '<p class="muted">Ingen treff i lokal opplæringsdatabase.</p>';
}

function initWorkMode() {
  const notes = $('#workNotes');
  if (!notes) return;
  notes.value = workState.notes || '';
  $('#saveNotes').addEventListener('click', () => { workState.notes = notes.value; addHistory('Lagret egne notater'); });
  $('#saveCustomer').addEventListener('click', () => {
    const name = $('#customerName').value.trim(); const engine = $('#customerEngine').value.trim();
    if (!name && !engine) return;
    workState.customers.unshift({ id: Date.now(), name, engine, date: new Date().toISOString() });
    $('#customerName').value = ''; $('#customerEngine').value = '';
    addHistory('Lagret kundeoppslag');
  });
  $('#addFavorite').addEventListener('click', () => {
    const value = $('#favoriteInput').value.trim(); if (!value) return;
    workState.favorites.unshift({ id: Date.now(), value, date: new Date().toISOString() }); $('#favoriteInput').value = ''; addHistory('La til favoritt');
  });
  $('#addTodo').addEventListener('click', () => {
    const value = $('#todoInput').value.trim(); if (!value) return;
    workState.todos.unshift({ id: Date.now(), value, done: false, date: new Date().toISOString() }); $('#todoInput').value = ''; addHistory('La til huskelistepunkt');
  });
  $('#addLog').addEventListener('click', () => {
    const value = $('#logInput').value.trim(); if (!value) return;
    workState.logs.unshift({ id: Date.now(), value, date: new Date().toISOString() }); $('#logInput').value = ''; addHistory('Lagret kundelogg');
  });
  $('#exportWorkData').addEventListener('click', () => {
    const blob = new Blob([JSON.stringify(workState, null, 2)], { type: 'application/json' });
    const a = document.createElement('a'); a.href = URL.createObjectURL(blob); a.download = 'marine-arbeidsmodus-data.json'; a.click(); URL.revokeObjectURL(a.href);
    addHistory('Eksporterte arbeidsdata');
  });
  $('#importWorkData').addEventListener('change', event => {
    const file = event.target.files[0]; if (!file) return;
    const reader = new FileReader();
    reader.onload = () => { try { Object.assign(workState, JSON.parse(reader.result)); addHistory('Importerte arbeidsdata'); } catch (_) { alert('Kunne ikke importere filen.'); } };
    reader.readAsText(file);
  });
  $('#notifyDaily').addEventListener('click', requestDailyNotification);
  document.addEventListener('click', event => {
    const partFav = event.target.closest('.add-part-favorite');
    if (partFav) { workState.favorites.unshift({ id: Date.now(), value: partFav.dataset.part, date: new Date().toISOString() }); addHistory('La til reservedel som favoritt'); }
    const done = event.target.closest('[data-toggle-todo]');
    if (done) { const item = workState.todos.find(t => String(t.id) === done.dataset.toggleTodo); if (item) item.done = !item.done; addHistory('Oppdaterte huskeliste'); }
    const remove = event.target.closest('[data-remove-work]');
    if (remove) { removeWorkItem(remove.dataset.removeWork, remove.dataset.id); }
  });
  renderWorkMode();
}
function removeWorkItem(type, id) {
  if (!workState[type]) return;
  workState[type] = workState[type].filter(item => String(item.id) !== String(id));
  addHistory('Fjernet element fra arbeidsmodus');
}
function todayLearning() {
  const day = Math.floor((Date.now() - new Date(new Date().getFullYear(),0,0)) / 86400000);
  const q = PLATFORM.quizzes[(day - 1) % PLATFORM.quizzes.length];
  const question = q.questions[(day - 1) % q.questions.length];
  return { chapter: q.chapter, title: q.title, question: question.question, answer: question.choices[question.answer], explanation: question.explanation };
}
function renderWorkMode() {
  const daily = todayLearning();
  const dailyHost = $('#dailyLearning');
  if (dailyHost) dailyHost.innerHTML = `<p><strong>Kapittel ${daily.chapter}</strong> · ${escapeHtml(daily.question)}</p><p class="muted">Mentorsvar: ${escapeHtml(daily.answer)}</p>`;
  renderList('customerList', workState.customers, item => `<strong>${escapeHtml(item.name || 'Uten navn')}</strong><span>${escapeHtml(item.engine || '')}</span><em>${new Date(item.date).toLocaleString('nb-NO')}</em>`, 'customers');
  renderList('favoriteList', workState.favorites, item => `<span>${escapeHtml(item.value)}</span>`, 'favorites');
  renderList('todoList', workState.todos, item => `<button class="mini ${item.done ? 'done' : ''}" data-toggle-todo="${item.id}">${item.done ? '✓' : '○'}</button><span>${escapeHtml(item.value)}</span>`, 'todos');
  renderList('logList', workState.logs, item => `<span>${escapeHtml(item.value)}</span><em>${new Date(item.date).toLocaleString('nb-NO')}</em>`, 'logs');
}
function renderList(id, items, render, type) {
  const host = $('#' + id); if (!host) return;
  host.innerHTML = items.slice(0, 12).map(item => `<div class="work-item">${render(item)}<button class="mini danger" data-remove-work="${type}" data-id="${item.id}">Fjern</button></div>`).join('') || '<p class="muted">Ingen lagrede elementer.</p>';
}
async function requestDailyNotification() {
  const daily = todayLearning();
  if (!('Notification' in window)) { alert('Varsler støttes ikke i denne nettleseren.'); return; }
  const permission = await Notification.requestPermission();
  if (permission === 'granted') new Notification('Dagens marine læring', { body: daily.question, icon: './icon.svg' });
}

function initPhaseModules() {
  initPwa();
  initInteractiveDiagrams();
  initPartsDatabase();
  initWorkMode();
}


