const TRAINER_KEY = 'marineTrainer.v1';
let currentTrainerSession = null;
let currentFlashcardIndex = 0;
let currentFlashcardSession = null;
let selectedTrainerLessonId = null;

function loadTrainerState() {
  const defaults = { xp: 0, completedLessons: [], completedLevels: [], answered: 0, correct: 0, wrongQueue: [], badges: [], lastTrainDate: null, streak: 0, lessonScores: {}, levelScores: {}, levelMistakes: {}, dailyGoal: 60, activeLevel: 1, flashcardsAnswered: 0, flashcardsKnown: 0, flashcardReviewQueue: [], flashcardSessions: [] };
  try {
    return Object.assign(defaults, JSON.parse(localStorage.getItem(TRAINER_KEY) || '{}'));
  } catch (_) {
    return defaults;
  }
}
const trainerState = loadTrainerState();
function saveTrainerState() { localStorage.setItem(TRAINER_KEY, JSON.stringify(trainerState)); }
function trainerLevel() {
  return TRAINER_DATA.xpLevels.find(l => trainerState.xp >= l.min && trainerState.xp <= l.max) || TRAINER_DATA.xpLevels[TRAINER_DATA.xpLevels.length - 1];
}
function xpForDifficulty(difficulty) { return { easy: 10, medium: 20, hard: 40, case: 60 }[difficulty] || 10; }
function updateTrainerStreak() {
  const today = new Date().toISOString().slice(0,10);
  if (trainerState.lastTrainDate === today) return;
  const yesterday = new Date(Date.now() - 86400000).toISOString().slice(0,10);
  trainerState.streak = trainerState.lastTrainDate === yesterday ? trainerState.streak + 1 : 1;
  trainerState.lastTrainDate = today;
}
function trainerNextLesson() {
  for (const level of TRAINER_DATA.path) {
    for (const lesson of level.lessons) {
      if (!trainerState.completedLessons.includes(lesson.id)) return lesson;
    }
  }
  return TRAINER_DATA.path[0].lessons[0];
}
function trainerLevelData(levelNumber) {
  return TRAINER_DATA.path.find(level => Number(level.level) === Number(levelNumber));
}
function trainerIsLevelPassed(levelNumber) {
  return trainerState.completedLevels.includes(Number(levelNumber));
}
function trainerIsLevelUnlocked(levelNumber) {
  const n = Number(levelNumber);
  return n === 1 || trainerIsLevelPassed(n - 1);
}
function trainerNextLevel() {
  return TRAINER_DATA.path.find(level => trainerIsLevelUnlocked(level.level) && !trainerIsLevelPassed(level.level)) || TRAINER_DATA.path[TRAINER_DATA.path.length - 1];
}
function trainerLevelPercent() {
  return Math.round((trainerState.completedLevels.length / TRAINER_DATA.path.length) * 100);
}
function trainerLessons() {
  return TRAINER_DATA.path.flatMap(level => level.lessons || []);
}
function trainerLessonById(id) {
  return trainerLessons().find(lesson => lesson.id === id);
}
function setTrainerError(message) {
  setTrainerStatus(message, true);
  const host = $('#trainer-lesson-screen') || $('#trainerQuiz');
  if (!host) return;
  showTrainerLessonScreen();
  host.innerHTML = `<div class="trainer-error"><strong>Kan ikke starte leksjonen.</strong><p>${escapeHtml(message)}</p></div>`;
}
function setTrainerStatus(message, isError = false) {
  const status = $('#trainerStatus');
  if (!status) return;
  status.textContent = message;
  status.classList.toggle('error', isError);
}
function handleTrainerStart(id, source = 'knapp') {
  setTrainerStatus(`Starter Trainer-level fra ${source} ...`);
  try {
    startTrainerLevel(id || trainerNextLevel().level);
  } catch (error) {
    setTrainerError(`Klikket ble registrert, men level kunne ikke åpnes: ${error?.message || error}`);
  }
}
function trainerClickTarget(event, selector) {
  const target = event.target;
  return target && typeof target.closest === 'function' ? target.closest(selector) : null;
}
function startSelectedTrainerLevel(source = 'Start leksjon-knappen') {
  handleTrainerStart(trainerState.activeLevel || trainerNextLevel().level, source);
}
function handleTrainerLevelButton(event, button) {
  event.preventDefault();
  event.stopPropagation();
  if (!button || button.disabled) return;
  const levelNumber = Number(button.dataset.trainerLevel);
  if (!levelNumber) {
    setTrainerError('Klikket ble registrert, men levelnummer mangler på knappen.');
    return;
  }
  handleTrainerStart(levelNumber, 'Start level-knappen');
}
function bindTrainerStartButtons() {
  $$('#startTrainerLesson').forEach(button => {
    if (button.dataset.boundTrainerStart === 'true') return;
    button.dataset.boundTrainerStart = 'true';
    button.addEventListener('click', event => {
      event.preventDefault();
      event.stopPropagation();
      startSelectedTrainerLevel('Start leksjon-knappen');
    });
  });
}
function bindTrainerLevelButtons() {
  $$('#trainerPath [data-trainer-level]').forEach(button => {
    if (button.dataset.boundTrainerLevel === 'true') return;
    button.dataset.boundTrainerLevel = 'true';
    button.addEventListener('click', event => handleTrainerLevelButton(event, button));
  });
}
function initTrainer() {
  if (!$('#view-trainer')) return;
  bindTrainerStartButtons();
  bindTrainerLevelButtons();
  $('#startReview')?.addEventListener('click', startReviewSession);
  $('#openFlashcards')?.addEventListener('click', event => {
    event.preventDefault();
    startTrainerFlashcards();
  });
  document.addEventListener('click', event => {
    const start = trainerClickTarget(event, '[data-trainer-start]');
    if (start) {
      handleTrainerStart(start.dataset.trainerStart === 'next' ? trainerNextLevel().level : trainerState.activeLevel || trainerNextLevel().level, 'Start leksjon-knappen');
      return;
    }
    const level = trainerClickTarget(event, '[data-trainer-level]');
    if (level) {
      handleTrainerStart(Number(level.dataset.trainerLevel), 'Learning Path');
      return;
    }
    const lesson = trainerClickTarget(event, '[data-trainer-lesson]');
    if (lesson) {
      selectedTrainerLessonId = lesson.dataset.trainerLesson;
      const selected = trainerLessonById(selectedTrainerLessonId);
      handleTrainerStart(selected?.level || trainerNextLevel().level, 'Learning Path');
      return;
    }
    const choice = trainerClickTarget(event, '[data-trainer-choice]');
    if (choice) selectTrainerChoice(Number(choice.dataset.trainerChoice));
    const check = trainerClickTarget(event, '#trainerCheckAnswer');
    if (check) answerTrainerQuestion();
    const answer = trainerClickTarget(event, '[data-trainer-answer]');
    if (answer) answerTrainerQuestion(Number(answer.dataset.trainerAnswer));
    const next = trainerClickTarget(event, '#trainerNextQuestion');
    if (next) advanceTrainerQuestion();
    const back = trainerClickTarget(event, '#trainerBackToPath');
    if (back) closeTrainerLessonScreen();
    const retryLevel = trainerClickTarget(event, '[data-trainer-retry-level]');
    if (retryLevel) startTrainerLevel(Number(retryLevel.dataset.trainerRetryLevel), true);
    const nextLevel = trainerClickTarget(event, '[data-trainer-next-level]');
    if (nextLevel) startTrainerLevel(Number(nextLevel.dataset.trainerNextLevel));
  });
  renderTrainer();
}
function renderTrainer() {
  const level = trainerLevel();
  const percent = trainerLevelPercent();
  const next = trainerNextLevel();
  if ($('#trainerXp')) $('#trainerXp').textContent = trainerState.xp;
  if ($('#trainerLevel')) $('#trainerLevel').textContent = level.level;
  if ($('#trainerStreak')) $('#trainerStreak').textContent = `🔥 ${trainerState.streak}`;
  if ($('#trainerPercent')) $('#trainerPercent').textContent = percent + '%';
  if ($('#trainerProgressBar')) $('#trainerProgressBar').style.width = percent + '%';
  if ($('#trainerNext')) $('#trainerNext').textContent = `Neste anbefalte level: Level ${next.level} - ${next.title}. Bestå med minst 70 %. Dagens mål: ${trainerState.dailyGoal} XP.`;
  renderTrainerPath();
  renderTrainerBadges();
  renderTrainerProgressDetails();
  if (!$('#trainerQuiz')?.textContent.trim()) $('#trainerQuiz').innerHTML = '<p class="muted">Start neste leksjon for å få spørsmål. Feil svar legges automatisk i Review.</p>';
  if ($('#trainerStatus') && !$('#trainerStatus').textContent.trim()) setTrainerStatus('Trainer klar.');
  bindTrainerStartButtons();
  bindTrainerLevelButtons();
}
function renderTrainerPath() {
  const host = $('#trainerPath'); if (!host) return;
  host.innerHTML = TRAINER_DATA.path.map(level => {
    const locked = !trainerIsLevelUnlocked(level.level);
    const passed = trainerIsLevelPassed(level.level);
    const score = trainerState.levelScores[level.level];
    const questions = questionsForLevel(level).length;
    const lessons = level.lessons.map(lesson => `<span>${escapeHtml(lesson.title)}</span>`).join('');
    return `<article class="trainer-level ${locked ? 'locked' : ''} ${passed ? 'done' : ''}">
      <div class="trainer-level-head">
        <div><strong>Level ${level.level}: ${escapeHtml(level.title)}</strong><p>${escapeHtml(level.description)}</p></div>
        <span class="level-pill">${locked ? 'Låst' : passed ? 'Bestått' : 'Åpen'}</span>
      </div>
      <div class="level-meta"><span>${questions} spørsmål</span><span>${score ? `${score.percent}% sist` : '70% for å bestå'}</span><span>${level.lessons.length} tema</span></div>
      <div class="trainer-lessons">${lessons}</div>
      <button class="trainer-level-start" data-trainer-level="${level.level}" ${locked ? 'disabled' : ''}>${locked ? `Fullfør Level ${Number(level.level) - 1} først` : passed ? 'Repeter level' : 'Start level'}</button>
    </article>`;
  }).join('');
}
function normalizedTrainerQuestion(q) {
  if (!q || !Array.isArray(q.choices) || q.choices.length < 2) return null;
  const answer = Number(q.answer);
  if (!Number.isInteger(answer) || answer < 0 || answer >= q.choices.length) return null;
  const prompt = q.prompt || q.question;
  if (!prompt) return null;
  return Object.assign({}, q, { prompt, answer, difficulty: q.difficulty || 'easy', type: q.type || 'multiple', explanation: q.explanation || 'Ingen forklaring er registrert for dette spørsmålet.' });
}
function uniqueTrainerQuestions(questions) {
  const seen = new Set();
  return questions.filter(q => {
    const key = q.id || q.prompt;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}
function questionsForLevel(level, retryMistakes = false) {
  const validQuestions = TRAINER_DATA.questions.map(normalizedTrainerQuestion).filter(Boolean);
  if (retryMistakes) {
    const missed = (trainerState.levelMistakes[level.level] || []).map(id => validQuestions.find(q => q.id === id)).filter(Boolean);
    return missed.length ? missed.slice(0, 10) : [];
  }
  const chapters = (level.lessons || []).map(lesson => String(lesson.chapter || '').padStart(2, '0'));
  const byChapter = validQuestions.filter(q => chapters.some(chapter => q.tags?.includes(chapter) || q.lesson === chapter));
  const byTitle = validQuestions.filter(q => {
    const text = `${q.prompt} ${(q.tags || []).join(' ')}`.toLowerCase();
    return (level.lessons || []).some(lesson => text.includes(String(lesson.title).toLowerCase().split(' ')[0]));
  });
  const general = validQuestions.filter(q => !byChapter.includes(q) && !byTitle.includes(q));
  return uniqueTrainerQuestions([...shuffle(byChapter), ...shuffle(byTitle), ...shuffle(general)]).slice(0, 10);
}
function questionsForLesson(lesson) {
  const chapter = String(lesson.chapter || '').padStart(2, '0');
  const validQuestions = TRAINER_DATA.questions.map(normalizedTrainerQuestion).filter(Boolean);
  const byChapter = validQuestions.filter(q => q.tags?.includes(chapter) || q.tags?.includes(lesson.chapter) || q.lesson === chapter || q.lesson === lesson.id);
  const general = validQuestions.filter(q => !byChapter.includes(q));
  return shuffle([...byChapter.slice(0, 4), ...general.slice(0, 4)]).slice(0, 7);
}
function startTrainerLesson(id) {
  const lesson = trainerLessonById(id);
  if (!lesson) {
    setTrainerError(`Fant ikke Trainer-leksjonen "${id || 'ukjent'}". Kontroller at leksjonen finnes i læringsstien.`);
    return;
  }
  startTrainerLevel(lesson.level);
}
function trainerShell() {
  return $('#view-trainer .trainer-shell');
}
function showTrainerLessonScreen() {
  const screen = $('#trainer-lesson-screen');
  trainerShell()?.classList.remove('flashcards-active');
  trainerShell()?.classList.add('lesson-active');
  screen?.classList.remove('hidden');
  screen?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}
function closeTrainerLessonScreen() {
  currentTrainerSession = null;
  trainerShell()?.classList.remove('lesson-active');
  const screen = $('#trainer-lesson-screen');
  if (screen) {
    screen.classList.add('hidden');
    screen.innerHTML = '';
  }
  renderTrainer();
  $('#view-trainer')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}
function showTrainerFlashcardScreen() {
  const screen = $('#trainer-flashcard-screen');
  trainerShell()?.classList.remove('lesson-active');
  trainerShell()?.classList.add('flashcards-active');
  screen?.classList.remove('hidden');
  screen?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}
function closeTrainerFlashcardScreen() {
  currentFlashcardSession = null;
  trainerShell()?.classList.remove('flashcards-active');
  const screen = $('#trainer-flashcard-screen');
  if (screen) {
    screen.classList.add('hidden');
    screen.innerHTML = '';
  }
  renderTrainer();
  $('#view-trainer')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
}
function setTrainerFlashcardError(message) {
  setTrainerStatus(message, true);
  showTrainerFlashcardScreen();
  const host = $('#trainer-flashcard-screen');
  if (host) host.innerHTML = `<div class="trainer-error"><strong>Kan ikke åpne Flashcards.</strong><p>${escapeHtml(message)}</p><button id="trainerFlashcardBack" class="secondary">Tilbake til Trainer</button></div>`;
  bindTrainerFlashcardButtons();
}
function bindTrainerFlashcardButtons() {
  const host = $('#trainer-flashcard-screen');
  if (!host) return;
  const bind = (selector, handler) => {
    host.querySelectorAll(selector).forEach(button => {
      if (button.dataset.boundFlashcard === 'true') return;
      button.dataset.boundFlashcard = 'true';
      button.addEventListener('click', event => {
        event.preventDefault();
        event.stopPropagation();
        try {
          handler(button);
        } catch (error) {
          setTrainerFlashcardError(`JavaScript-feil i Flashcards: ${error?.message || error}`);
        }
      });
    });
  };
  bind('#trainerFlashcardReveal', () => revealTrainerFlashcard());
  bind('[data-flashcard-rating]', button => rateTrainerFlashcard(button.dataset.flashcardRating));
  bind('#trainerFlashcardNext', () => advanceTrainerFlashcard());
  bind('#trainerFlashcardFinish', () => finishTrainerFlashcards());
  bind('#trainerFlashcardBack', () => closeTrainerFlashcardScreen());
  bind('#trainerFlashcardRestart', () => startTrainerFlashcards());
}
function startTrainerLevel(levelNumber, retryMistakes = false) {
  const level = trainerLevelData(levelNumber);
  if (!level) {
    setTrainerError(`Fant ikke Trainer-level "${levelNumber || 'ukjent'}".`);
    return;
  }
  if (!trainerIsLevelUnlocked(level.level)) {
    setTrainerError(`Level ${level.level} er låst. Bestå Level ${Number(level.level) - 1} med minst 70 % først.`);
    return;
  }
  const queue = questionsForLevel(level, retryMistakes);
  if (!queue.length) {
    setTrainerError(`Level ${level.level} mangler spørsmål. Kontroller Trainer-spørsmål for temaene i "${level.title}".`);
    return;
  }
  trainerState.activeLevel = level.level;
  selectedTrainerLessonId = level.lessons?.[0]?.id || null;
  currentTrainerSession = { mode: retryMistakes ? 'retry' : 'level', level, lesson: level.lessons?.[0] || null, queue, index: 0, correct: 0, earned: 0, answered: false, selectedIndex: null, mistakes: [] };
  saveTrainerState();
  showTrainerLessonScreen();
  renderTrainerQuestion();
  setTrainerStatus(`Level ${level.level} åpnet: ${level.title}.`);
}
function startReviewSession() {
  const validQuestions = TRAINER_DATA.questions.map(normalizedTrainerQuestion).filter(Boolean);
  const queued = trainerState.wrongQueue.slice(0, 12).map(id => validQuestions.find(q => q.id === id)).filter(Boolean);
  const queue = queued.length ? queued : shuffle(validQuestions).slice(0, 8);
  if (!queue.length) {
    setTrainerError('Review kan ikke startes fordi Trainer mangler gyldige spørsmål.');
    return;
  }
  currentTrainerSession = { mode: 'review', lesson: null, queue, index: 0, correct: 0, earned: 0, answered: false, selectedIndex: null, mistakes: [] };
  showTrainerLessonScreen();
  renderTrainerQuestion();
}
function renderTrainerQuestion() {
  const host = $('#trainer-lesson-screen'); if (!host || !currentTrainerSession) return;
  if (currentTrainerSession.index >= currentTrainerSession.queue.length) return finishTrainerSession();
  const q = currentTrainerSession.queue[currentTrainerSession.index];
  if (!q) {
    setTrainerError('Spørsmålsdata mangler for denne leksjonen.');
    return;
  }
  const choices = shuffle(q.choices.map((text, original) => ({ text, original })));
  currentTrainerSession.current = { q, choices, correctIndex: choices.findIndex(c => c.original === q.answer) };
  currentTrainerSession.answered = false;
  currentTrainerSession.selectedIndex = null;
  const level = currentTrainerSession.level;
  const progress = Math.round(((currentTrainerSession.index + 1) / currentTrainerSession.queue.length) * 100);
  host.innerHTML = `<div class="trainer-question lesson-card">
    <div class="lesson-topbar"><button id="trainerBackToPath" class="secondary">Tilbake</button><span class="kicker">${level ? `Level ${level.level}` : 'Review'}</span></div>
    <div class="level-session-head"><strong>${level ? escapeHtml(level.title) : 'Repeter feil svar'}</strong><span>${labelForQuestionType(q.type)} · ${q.difficulty} · ${xpForDifficulty(q.difficulty)} XP</span></div>
    <div class="progress-rail trainer-question-progress"><span style="width:${progress}%"></span></div>
    <div class="quiz-meta"><strong>Spørsmål ${currentTrainerSession.index + 1} av ${currentTrainerSession.queue.length}</strong><span>${currentTrainerSession.correct} riktige så langt</span></div>
    <h3>${escapeHtml(q.prompt)}</h3>
    <div class="trainer-answer-grid">${choices.map((c, i) => `<button data-trainer-choice="${i}" aria-pressed="false">${escapeHtml(c.text)}</button>`).join('')}</div>
    <button id="trainerCheckAnswer" disabled>Sjekk svar</button>
    <div id="trainerFeedback" class="trainer-feedback hidden"></div>
    <p class="muted">Velg ett svaralternativ og trykk Sjekk svar.</p>
  </div>`;
}
function selectTrainerChoice(index) {
  if (!currentTrainerSession || currentTrainerSession.answered) return;
  currentTrainerSession.selectedIndex = index;
  $$('#trainer-lesson-screen [data-trainer-choice]').forEach((btn, i) => {
    const selected = i === index;
    btn.classList.toggle('selected', selected);
    btn.setAttribute('aria-pressed', String(selected));
  });
  const check = $('#trainerCheckAnswer');
  if (check) check.disabled = false;
}
function advanceTrainerQuestion() {
  if (!currentTrainerSession) return;
  currentTrainerSession.index += 1;
  currentTrainerSession.answered = false;
  currentTrainerSession.selectedIndex = null;
  renderTrainerQuestion();
}
function labelForQuestionType(type) {
  return { multiple:'Flervalg', truefalse:'Sant/usant', match:'Match komponent', partnumber:'Finn delenummer', system:'Identifiser system', 'customer-case':'Kundescenario', 'workshop-case':'Verkstedscenario', flashcard:'Flashcard' }[type] || 'Spørsmål';
}
function trainerRememberPoint(q) {
  const tags = (q.tags || []).join(', ');
  if (/serienummer|motornummer|engine|serial/i.test(`${q.prompt} ${tags}`)) return 'Husk dette: Motoridentitet skal bekreftes før delnummer eller feilsvar gis.';
  if (/kunde|support|kommunikasjon|klage/i.test(`${q.prompt} ${tags}`)) return 'Husk dette: Gode kundesvar skiller fakta, antakelser, forbehold og neste steg.';
  if (/del|part|reservedel|supersession|kit/i.test(`${q.prompt} ${tags}`)) return 'Husk dette: Delnummer må alltid kobles til variant, posisjon, antall og produsentkilde.';
  return 'Husk dette: Start med dokumenterte fakta, ikke magefølelse, når du velger neste handling.';
}
function answerTrainerQuestion(index) {
  if (!currentTrainerSession || currentTrainerSession.answered) return;
  const cur = currentTrainerSession.current;
  if (!cur) {
    setTrainerError('Spørsmålet ble ikke lastet riktig. Start leksjonen på nytt.');
    return;
  }
  const selectedIndex = Number.isInteger(index) ? index : currentTrainerSession.selectedIndex;
  if (!Number.isInteger(selectedIndex)) {
    setTrainerError('Velg et svaralternativ før du sjekker svaret.');
    return;
  }
  const ok = selectedIndex === cur.correctIndex;
  currentTrainerSession.answered = true;
  trainerState.answered += 1;
  if (ok) {
    const xp = xpForDifficulty(cur.q.difficulty);
    trainerState.xp += xp;
    currentTrainerSession.earned += xp;
    currentTrainerSession.correct += 1;
    trainerState.correct += 1;
  } else if (!trainerState.wrongQueue.includes(cur.q.id)) {
    trainerState.wrongQueue.push(cur.q.id);
  }
  if (!ok) currentTrainerSession.mistakes.push(cur.q.id);
  unlockTrainerBadges(cur.q, ok);
  saveTrainerState();
  const feedback = $('#trainerFeedback');
  const correctText = cur.choices[cur.correctIndex]?.text || cur.q.choices[cur.q.answer];
  const selectedText = cur.choices[selectedIndex]?.text || '';
  if (feedback) {
    feedback.classList.remove('hidden');
    feedback.classList.toggle('correct', ok);
    feedback.classList.toggle('wrong', !ok);
    feedback.innerHTML = `<h4>${ok ? 'Riktig svar' : 'Ikke helt riktig'}</h4>
      <p>${escapeHtml(cur.q.explanation)}</p>
      <p><strong>Hvorfor riktig svar er riktig:</strong> ${escapeHtml(correctText)} følger den dokumenterte arbeidsmåten for temaet.</p>
      ${ok ? '' : `<p><strong>Hvorfor ditt svar er feil:</strong> ${escapeHtml(selectedText)} mangler nødvendig kontroll eller bygger på en antakelse som kan gi feil del, feil diagnose eller svakt kundesvar.</p>`}
      <p><strong>${escapeHtml(trainerRememberPoint(cur.q))}</strong></p>
      <button id="trainerNextQuestion">Neste spørsmål</button>`;
  }
  const check = $('#trainerCheckAnswer');
  if (check) check.disabled = true;
  $$('#trainer-lesson-screen [data-trainer-choice], #trainer-lesson-screen [data-trainer-answer]').forEach((btn, i) => {
    btn.disabled = true;
    btn.classList.toggle('correct', i === cur.correctIndex);
    btn.classList.toggle('wrong', i === selectedIndex && !ok);
  });
  renderTrainerBadges();
  renderTrainerProgressDetails();
}
function finishTrainerSession() {
  const host = $('#trainer-lesson-screen');
  const session = currentTrainerSession;
  const percent = Math.round((session.correct / session.queue.length) * 100);
  const passed = percent >= 70;
  const levelNumber = session.level?.level;
  const isLevelSession = (session.mode === 'level' || session.mode === 'retry') && levelNumber;
  if (isLevelSession) {
    trainerState.levelScores[levelNumber] = { correct: session.correct, total: session.queue.length, percent, xp: session.earned, date: new Date().toISOString() };
    trainerState.levelMistakes[levelNumber] = session.mistakes.slice();
    if (passed && !trainerState.completedLevels.includes(Number(levelNumber))) trainerState.completedLevels.push(Number(levelNumber));
    (session.level.lessons || []).forEach(lesson => {
      if (passed && !trainerState.completedLessons.includes(lesson.id)) trainerState.completedLessons.push(lesson.id);
    });
  }
  updateTrainerStreak();
  trainerState.wrongQueue = trainerState.wrongQueue.slice(-80);
  saveTrainerState();
  const repeatTopics = uniqueTrainerQuestions(session.mistakes.map(id => session.queue.find(q => q.id === id)).filter(Boolean)).map(q => labelForQuestionType(q.type)).slice(0, 4);
  const nextLevel = trainerLevelData(Number(levelNumber || 1) + 1);
  currentTrainerSession = null;
  renderTrainer();
  if (!isLevelSession) {
    host.innerHTML = `<div class="quiz-result trainer-level-result">
      <span class="kicker">Review ferdig</span>
      <h3>Resultat for repetisjon</h3>
      <div class="result-score"><strong>${session.correct} av ${session.queue.length}</strong><span>${percent}%</span><span>${session.earned} XP opptjent</span></div>
      <p>Feil svar ligger fortsatt i Review-køen til de repeteres riktig i senere økter.</p>
      <div class="action-row">
        <button id="startReview">Start ny review</button>
        <button data-trainer-start="next" class="secondary">Start neste level</button>
      </div>
    </div>`;
    $('#startReview')?.addEventListener('click', startReviewSession);
    setTrainerStatus(`Review ferdig: ${percent} %.`);
    return;
  }
  host.innerHTML = `<div class="quiz-result trainer-level-result">
    <button id="trainerBackToPath" class="secondary">Tilbake</button>
    <span class="kicker">${passed ? 'Level bestått' : 'Level ikke bestått'}</span>
    <h3>Resultat for Level ${levelNumber}: ${escapeHtml(session.level?.title || 'Trainer')}</h3>
    <div class="result-score"><strong>${session.correct} av ${session.queue.length}</strong><span>${percent}%</span><span>${session.earned} XP opptjent</span></div>
    <p>${passed ? 'Bra jobbet. Neste level er låst opp.' : 'Du trenger minst 70 % for å låse opp neste level.'}</p>
    <h4>Tema du bør repetere</h4>
    <ul>${(repeatTopics.length ? repeatTopics : ['Ingen tydelige svake tema i denne runden.']).map(topic => `<li>${escapeHtml(topic)}</li>`).join('')}</ul>
    <div class="action-row">
      <button data-trainer-retry-level="${levelNumber}" ${session.mistakes.length ? '' : 'disabled'}>Repeter feil svar</button>
      <button data-trainer-next-level="${nextLevel?.level || levelNumber}" class="secondary" ${passed && nextLevel ? '' : 'disabled'}>Gå til neste level</button>
    </div>
  </div>`;
  $('#startReview')?.addEventListener('click', startReviewSession);
  setTrainerStatus(`Level ${levelNumber} ferdig: ${percent} %. ${passed ? 'Neste level er låst opp.' : 'Repeter feil svar og prøv igjen.'}`);
}
function unlockTrainerBadges(q, ok) {
  const add = id => { if (!trainerState.badges.includes(id)) trainerState.badges.push(id); };
  if (trainerState.completedLessons.length > 0 || trainerState.answered > 0) add('first-lesson');
  if (trainerState.answered >= 100) add('questions-100');
  if (trainerState.streak >= 7) add('streak-7');
  if (trainerState.streak >= 30) add('streak-30');
  const tags = (q.tags || []).join(' ').toLowerCase();
  if (ok && tags.includes('common rail')) add('common-rail');
  if (ok && (tags.includes('turbo') || tags.includes('luft'))) add('turbo');
  if (ok && q.type === 'customer-case') add('support');
  if (ok && q.type === 'workshop-case') add('workshop');
  if (ok && tags.includes('volvo')) add('volvo');
  if (ok && tags.includes('cummins')) add('cummins');
  if (ok && (tags.includes('caterpillar') || tags.includes('cat'))) add('cat');
  if (ok && tags.includes('man')) add('man');
  if (ok && tags.includes('yanmar')) add('yanmar');
}
function renderTrainerBadges() {
  const host = $('#trainerBadges'); if (!host) return;
  host.innerHTML = TRAINER_DATA.badges.map(b => `<div class="badge ${trainerState.badges.includes(b.id) ? 'earned' : ''}"><strong>${escapeHtml(b.title)}</strong><span>${escapeHtml(b.description)}</span></div>`).join('');
}
function renderTrainerProgressDetails() {
  const host = $('#trainerProgressDetails'); if (!host) return;
  const totalLessons = TRAINER_DATA.path.reduce((sum,l) => sum + l.lessons.length, 0);
  const percent = trainerLevelPercent();
  const activeScore = trainerState.levelScores[trainerState.activeLevel];
  host.innerHTML = `<table><thead><tr><th>Målepunkt</th><th>Status</th></tr></thead><tbody><tr><td>XP</td><td>${trainerState.xp}</td></tr><tr><td>XP-level</td><td>${trainerLevel().level}</td></tr><tr><td>Level-progresjon</td><td>${percent}%</td></tr><tr><td>Beståtte levels</td><td>${trainerState.completedLevels.length} av ${TRAINER_DATA.path.length}</td></tr><tr><td>Fullførte leksjonstema</td><td>${trainerState.completedLessons.length} av ${totalLessons}</td></tr><tr><td>Siste level-score</td><td>${activeScore ? `${activeScore.correct} av ${activeScore.total} (${activeScore.percent}%)` : 'Ingen fullført level ennå'}</td></tr><tr><td>Fullførte spørsmål</td><td>${trainerState.answered} besvart, ${trainerState.correct} riktige</td></tr><tr><td>Flashcards</td><td>${trainerState.flashcardsAnswered || 0} besvart, ${trainerState.flashcardsKnown || 0} kunne</td></tr><tr><td>Review-kø</td><td>${trainerState.wrongQueue.length} spørsmål / ${(trainerState.flashcardReviewQueue || []).length} flashcards</td></tr><tr><td>Badges</td><td>${trainerState.badges.length} av ${TRAINER_DATA.badges.length}</td></tr><tr><td>Dagens mål</td><td>${trainerState.dailyGoal} XP</td></tr></tbody></table>`;
}
function trainerFlashcardDeck() {
  if (!Array.isArray(TRAINER_FLASHCARDS) || !TRAINER_FLASHCARDS.length) return [];
  const reviewIds = trainerState.flashcardReviewQueue || [];
  const reviewCards = reviewIds.map(id => TRAINER_FLASHCARDS.find(card => card.id === id)).filter(Boolean);
  const freshCards = TRAINER_FLASHCARDS.filter(card => !reviewIds.includes(card.id));
  return uniqueById([...reviewCards, ...freshCards]).slice(0, 20);
}
function uniqueById(items) {
  const seen = new Set();
  return items.filter(item => {
    const key = item.id || item.question;
    if (seen.has(key)) return false;
    seen.add(key);
    return true;
  });
}
function startTrainerFlashcards() {
  try {
    const deck = trainerFlashcardDeck();
    if (!deck.length) {
      setTrainerFlashcardError('Fant ingen flashcard-data. Kontroller at search-index.js lastes fra /marine-learning-platform/ og at TRAINER_FLASHCARDS finnes.');
      return;
    }
    currentFlashcardSession = { deck, index: 0, revealed: false, currentRating: null, ratings: [], known: 0, unsure: 0, missed: 0, reviewIds: [] };
    showTrainerFlashcardScreen();
    renderTrainerFlashcard();
    setTrainerStatus(`Flashcards åpnet: ${deck.length} kort lastet.`);
  } catch (error) {
    setTrainerFlashcardError(`JavaScript-feil ved åpning av Flashcards: ${error?.message || error}`);
  }
}
function renderTrainerFlashcard() {
  const host = $('#trainer-flashcard-screen');
  if (!host || !currentFlashcardSession) return;
  const session = currentFlashcardSession;
  const card = session.deck[session.index];
  if (!card) return finishTrainerFlashcards();
  const total = session.deck.length;
  const progress = Math.round(((session.index + 1) / total) * 100);
  const answer = session.revealed ? `<div class="flashcard-back"><span class="kicker">Svar</span><p>${escapeHtml(card.answer)}</p></div>` : '';
  const ratingDisabled = session.revealed ? '' : 'disabled';
  host.innerHTML = `<article class="trainer-flashcard active-flashcard">
    <div class="lesson-topbar"><button id="trainerFlashcardBack" class="secondary">Tilbake til Trainer</button><span class="kicker">${escapeHtml(card.manufacturer || 'Flashcard')}</span></div>
    <div class="progress-rail trainer-question-progress"><span style="width:${progress}%"></span></div>
    <div class="quiz-meta"><strong>Kort ${session.index + 1} av ${total}</strong><span>${escapeHtml(card.category || 'repetisjon')}</span></div>
    <div class="flashcard-front"><span class="kicker">Spørsmål</span><h3>${escapeHtml(card.question)}</h3></div>
    ${answer}
    <div class="flashcard-actions">
      <button id="trainerFlashcardReveal" ${session.revealed ? 'disabled' : ''}>Vis svar</button>
      <button data-flashcard-rating="known" class="secondary ${session.currentRating === 'known' ? 'selected' : ''}" ${ratingDisabled}>Kunne</button>
      <button data-flashcard-rating="unsure" class="secondary ${session.currentRating === 'unsure' ? 'selected' : ''}" ${ratingDisabled}>Usikker</button>
      <button data-flashcard-rating="missed" class="secondary ${session.currentRating === 'missed' ? 'selected' : ''}" ${ratingDisabled}>Kunne ikke</button>
      <button id="trainerFlashcardNext" class="secondary" ${session.revealed ? '' : 'disabled'}>Neste kort</button>
      <button id="trainerFlashcardFinish" class="secondary">Avslutt økten</button>
    </div>
  </article>`;
  bindTrainerFlashcardButtons();
}
function revealTrainerFlashcard() {
  if (!currentFlashcardSession) return;
  currentFlashcardSession.revealed = true;
  renderTrainerFlashcard();
}
function rateTrainerFlashcard(rating) {
  if (!currentFlashcardSession || !currentFlashcardSession.revealed) return;
  const session = currentFlashcardSession;
  const card = session.deck[session.index];
  if (!card) return;
  const existing = session.ratings.find(item => item.id === card.id);
  if (existing) {
    if (existing.rating === 'known') session.known = Math.max(0, session.known - 1);
    if (existing.rating === 'unsure') session.unsure = Math.max(0, session.unsure - 1);
    if (existing.rating === 'missed') session.missed = Math.max(0, session.missed - 1);
    existing.rating = rating;
  }
  else session.ratings.push({ id: card.id, rating });
  session.currentRating = rating;
  if (rating === 'known') session.known += 1;
  if (rating === 'unsure') session.unsure += 1;
  if (rating === 'missed') session.missed += 1;
  if ((rating === 'unsure' || rating === 'missed') && !session.reviewIds.includes(card.id)) session.reviewIds.push(card.id);
  renderTrainerFlashcard();
}
function advanceTrainerFlashcard() {
  if (!currentFlashcardSession) return;
  currentFlashcardSession.index += 1;
  currentFlashcardSession.revealed = false;
  currentFlashcardSession.currentRating = null;
  if (currentFlashcardSession.index >= currentFlashcardSession.deck.length) finishTrainerFlashcards();
  else renderTrainerFlashcard();
}
function finishTrainerFlashcards() {
  const host = $('#trainer-flashcard-screen');
  const session = currentFlashcardSession;
  if (!host || !session) return;
  const answered = session.ratings.length;
  const known = session.ratings.filter(item => item.rating === 'known').length;
  const unsure = session.ratings.filter(item => item.rating === 'unsure').length;
  const missed = session.ratings.filter(item => item.rating === 'missed').length;
  const earned = known * 5 + unsure * 2;
  trainerState.xp += earned;
  trainerState.flashcardsAnswered += answered;
  trainerState.flashcardsKnown += known;
  const reviewSet = new Set([...(trainerState.flashcardReviewQueue || []), ...session.reviewIds]);
  trainerState.flashcardReviewQueue = [...reviewSet].slice(-120);
  trainerState.wrongQueue = uniqueById([...(trainerState.wrongQueue || []).map(id => ({ id })), ...session.reviewIds.map(id => ({ id }))]).map(item => item.id).slice(-120);
  trainerState.flashcardSessions.unshift({ date: new Date().toISOString(), answered, known, unsure, missed, xp: earned });
  trainerState.flashcardSessions = trainerState.flashcardSessions.slice(0, 20);
  updateTrainerStreak();
  saveTrainerState();
  currentFlashcardSession = null;
  renderTrainer();
  host.innerHTML = `<div class="quiz-result trainer-level-result">
    <span class="kicker">Flashcards fullført</span>
    <h3>Resultat for repetisjon</h3>
    <div class="result-score"><strong>${answered} kort</strong><span>${known} kunne</span><span>${earned} XP</span></div>
    <p>${unsure + missed} kort ble lagt i repetisjonskøen.</p>
    <div class="action-row">
      <button id="trainerFlashcardRestart">Start ny økt</button>
      <button id="trainerFlashcardBack" class="secondary">Tilbake til Trainer</button>
    </div>
  </div>`;
  bindTrainerFlashcardButtons();
  setTrainerStatus(`Flashcards fullført: ${answered} kort, ${earned} XP, ${unsure + missed} til review.`);
}
function initMarineTrainer() { initTrainer(); }

const WORK_SIM_KEY = 'marineWorkSimulator.v1';
