    troubleshooting: 'Feilsøking',
    email: 'E-postsimulator',
    warranty: 'Garantisak',
    workshop: 'Verksteddialog',
    time: 'Tidsutfordring',
    difficult: 'Vanskelig kunde',
    quiz: 'Quiz',
    daily: 'Daglig oppdrag'
