function renderWorkSimulator() {
  simEnsureToday();
  const accuracy = workSimState.total ? Math.round((workSimState.correct / workSimState.total) * 100) : 0;
  if ($('#simScore')) $('#simScore').textContent = workSimState.score;
  if ($('#simCasesDone')) $('#simCasesDone').textContent = workSimState.total;
  if ($('#simAccuracy')) $('#simAccuracy').textContent = accuracy + '%';
  if ($('#simStreak')) $('#simStreak').textContent = workSimState.sessionsToday;
  renderSimHistory();
}
function renderSimCase(simCase) {
  const host = $('#simCase');
  if (!host || !simCase) return;
  const details = simCase.details?.length ? `<div class="sim-details">${simCase.details.map(d => `<p>${escapeHtml(d)}</p>`).join('')}</div>` : '';
  const progress = currentDailySession && simCase.fromDaily ? `<div class="sim-daily-progress"><strong>Sak ${currentDailySession.completed + 1} av ${currentDailySession.total}</strong><span>${currentDailySession.xp} XP i dag</span></div>` : '';
  const image = simImageMarkup(simCase);
  const meta = `<div class="sim-meta"><span>${escapeHtml(simCase.channel || simChannelLabel(simCase.mode))}</span><span>${Number(simCase.points || 0)} poeng</span></div>`;
  if (simCase.type === 'email') {
    host.innerHTML = `<article class="sim-case"><span class="kicker">${simModeLabel(simCase.mode)}</span><h3>${escapeHtml(simCase.title)}</h3>${meta}${progress}<p>${escapeHtml(simCase.intro)}</p>${image}${details}<h4>${escapeHtml(simCase.question)}</h4><textarea id="simEmailText" class="sim-email-box" rows="8" placeholder="Skriv kundesvar her..."></textarea><button id="simEvaluateEmail">Vurder svar</button></article>`;
    return;
  }
  host.innerHTML = `<article class="sim-case"><span class="kicker">${simModeLabel(simCase.mode)}</span><h3>${escapeHtml(simCase.title)}</h3>${meta}${progress}<p>${escapeHtml(simCase.intro)}</p>${image}${details}<h4>${escapeHtml(simCase.question)}</h4><div class="sim-choice-grid">${(simCase.choices || []).map((choice, idx) => `<button class="sim-choice" data-sim-answer="${idx}">${escapeHtml(choice.label)}</button>`).join('')}</div></article>`;
}
function startSimCase(mode = 'phone', fromDaily = false) {
  currentSimCase = createWorkSimCase(mode);
  currentSimCase.fromDaily = fromDaily;
  currentSimCase.answered = false;
  renderSimCase(currentSimCase);
  $('#simResult').innerHTML = '<p class="muted">Svar på saken for å få poeng, tilbakemelding og anbefalt repetisjon.</p>';
  $$('.sim-menu button').forEach(btn => btn.classList.toggle('active', btn.dataset.simMode === mode));
}
function evaluateSimAnswer(index) {
  if (!currentSimCase) return;
  const choice = currentSimCase.choices[index];
  if (!choice) return;
  finishSimCase(Boolean(choice.correct), choice.correct ? currentSimCase.points : 0, choice.feedback, currentSimCase.repeat || []);
  $$('#simCase [data-sim-answer]').forEach((btn, i) => {
    btn.disabled = true;
    btn.classList.toggle('correct', currentSimCase.choices[i]?.correct);
    btn.classList.toggle('wrong', i === index && !choice.correct);
  });
}
function evaluateSimEmail() {
  if (!currentSimCase) return;
  const text = normalize($('#simEmailText')?.value || '');
  const hits = currentSimCase.keywords.filter(keyword => text.includes(normalize(keyword)));
  const ok = hits.length >= 5;
  const missing = currentSimCase.keywords.filter(keyword => !hits.includes(keyword)).slice(0, 4);
  const feedback = ok
    ? `Godt svar. Du fikk med ${hits.length} viktige elementer: ${hits.join(', ')}.`
    : `Svaret mangler flere nøkkelpunkter. Legg særlig til: ${missing.join(', ')}.`;
  finishSimCase(ok, Math.min(currentSimCase.points, hits.length * 5), feedback, currentSimCase.repeat || []);
  $('#simEvaluateEmail').disabled = true;
}
function finishSimCase(ok, points, feedback, repeat) {
  if (!currentSimCase || currentSimCase.answered) return;
  currentSimCase.answered = true;
  simEnsureToday();
  workSimState.total += 1;
  workSimState.sessionsToday += 1;
  if (ok) workSimState.correct += 1;
  workSimState.score += points;
  const entry = {
    date: new Date().toISOString(),
    mode: currentSimCase.mode,
    title: currentSimCase.title,
    ok,
    points,
    feedback,
    repeat: repeat.slice(0, 4)
  };
  workSimState.history.unshift(entry);
  workSimState.history = workSimState.history.slice(0, 25);
  if (currentSimCase.fromDaily && currentDailySession) {
    currentDailySession.completed += 1;
    currentDailySession.xp += points;
    if (ok) currentDailySession.correct += 1;
    else currentDailySession.wrong += 1;
  }
  saveWorkSimState();
  renderSimResult(entry);
  renderWorkSimulator();
  if (currentSimCase.fromDaily) {
    const nextBtn = $('#simNextCase');
    if (nextBtn) nextBtn.textContent = workSimState.dailyQueue.length ? `Neste sak (${workSimState.dailyQueue.length} igjen)` : 'Vis dagens resultat';
  }
}
function renderSimResult(entry) {
  const host = $('#simResult');
  if (!host) return;
  const repeat = entry.repeat?.length ? entry.repeat.map(id => `<button class="secondary open-chapter" data-chapter="${id}">${escapeHtml(simChapterName(id))}</button>`).join('') : '<span class="muted">Ingen spesifikke kapitler foreslått.</span>';
  const dailyNext = currentSimCase?.fromDaily ? `<button id="simContinueDaily">${workSimState.dailyQueue.length ? 'Neste sak' : 'Vis dagens resultat'}</button>` : '';
  host.innerHTML = `<div class="sim-result ${entry.ok ? 'good' : 'warn'}"><h4>${entry.ok ? 'God håndtering' : 'Må forbedres'}</h4><p><strong>Konsekvens:</strong> ${entry.ok ? 'Kunden får tryggere svar, færre feilbestillinger og bedre fremdrift.' : 'Saken kan gi feil del, ny ventetid eller svak dokumentasjon hvis den håndteres slik.'}</p><p><strong>Forklaring:</strong> ${escapeHtml(entry.feedback)}</p><p><strong>Hvorfor svaret var ${entry.ok ? 'riktig' : 'feil'}:</strong> ${entry.ok ? 'Valget bygger på identifikasjon, dokumentasjon og kontroll før konklusjon.' : 'Valget hopper over nødvendig kontroll eller lover mer enn saken dokumenterer.'}</p><p><strong>${entry.points} poeng.</strong></p><div class="sim-feedback-grid"><div><strong>Hva gikk bra</strong><p>${entry.ok ? 'Du brukte dokumentasjon og struktur før beslutning.' : 'Du fikk saken videre og kan nå forbedre beslutningsgrunnlaget.'}</p></div><div><strong>Hva kan forbedres</strong><p>${entry.ok ? 'Fortsett å skrive tydelige forbehold og neste steg.' : 'Stopp tidligere ved manglende identifikasjon, og be om bilder/typeplate før del bekreftes.'}</p></div></div><div class="action-row">${dailyNext}${repeat}</div></div>`;
}
function renderSimHistory() {
  const host = $('#simHistory');
  if (!host) return;
  if (!workSimState.history.length) {
    host.innerHTML = '<p class="muted">Ingen simuleringer fullført ennå.</p>';
    return;
  }
  host.innerHTML = `<div class="sim-history-list">${workSimState.history.slice(0, 8).map(item => `<article class="sim-history-item"><strong>${escapeHtml(simModeLabel(item.mode))}: ${escapeHtml(item.title)}</strong><span>${item.ok ? 'Bestått' : 'Trenger øving'} · ${item.points} poeng · ${new Date(item.date).toLocaleDateString('nb-NO')}</span></article>`).join('')}</div>`;
}
function startSimDailyMission() {
  simEnsureToday();
  workSimState.dailyQueue = ['phone', 'phone', 'phone', 'workshop', 'workshop', 'warranty', 'quiz'];
  currentDailySession = { total: workSimState.dailyQueue.length, completed: 0, correct: 0, wrong: 0, xp: 0, started: new Date().toISOString() };
  saveWorkSimState();
  startNextDailyCase();
}
function startNextDailyCase() {
  simEnsureToday();
  const mode = workSimState.dailyQueue.shift();
  saveWorkSimState();
  if (!mode) {
    currentSimCase = null;
    const session = currentDailySession || { total: 0, completed: 0, correct: 0, wrong: 0, xp: 0 };
    const satisfaction = session.completed ? Math.max(0, Math.round((session.correct / session.completed) * 100)) : 0;
    const errorRate = session.completed ? Math.round((session.wrong / session.completed) * 100) : 0;
    $('#simCase').innerHTML = '<article class="sim-case"><span class="kicker">Daglig oppdrag</span><h3>Dagens arbeidspakke er fullført</h3><p>Du har gjennomført kundesaker, verkstedspørsmål, reklamasjon og quiz. Se resultatlisten for repetisjonspunkter.</p></article>';
    $('#simResult').innerHTML = `<div class="sim-result good"><h4>Daglig økt ferdig</h4><div class="sim-summary-grid"><div><strong>${session.xp}</strong><span>XP</span></div><div><strong>${satisfaction}%</strong><span>Kundetilfredshet</span></div><div><strong>${errorRate}%</strong><span>Feilprosent</span></div></div><p>Bruk anbefalte kapitler under for repetisjon før neste arbeidsøkt.</p></div>`;
    currentDailySession = null;
    renderWorkSimulator();
    return;
  }
  startSimCase(mode, true);
}
function continueSimCaseFlow() {
  if (currentSimCase?.fromDaily || currentDailySession) {
    if (currentSimCase && !currentSimCase.answered) {
      $('#simResult').innerHTML = '<div class="sim-result warn"><h4>Svar på saken først</h4><p>Velg et svaralternativ og les forklaringen før neste sak lastes.</p></div>';
      return;
    }
    startNextDailyCase();
    return;
  }
  if (workSimState.dailyQueue.length) startNextDailyCase();
  else startSimCase('phone');
}
function resetWorkSimulator() {
  if (!confirm('Vil du nullstille Work Simulator-resultater på denne enheten?')) return;
  workSimState.score = 0;
  workSimState.correct = 0;
  workSimState.total = 0;
  workSimState.sessionsToday = 0;
  workSimState.history = [];
  workSimState.dailyQueue = [];
  workSimState.lastDate = simTodayKey();
  saveWorkSimState();
  startSimCase('phone');
  renderWorkSimulator();
}
function initWorkSimulator() {
  if (!$('#view-work-simulator')) return;
  simEnsureToday();
  $$('.sim-menu [data-sim-mode]').forEach(btn => btn.addEventListener('click', () => startSimCase(btn.dataset.simMode)));
  $('#simStartDay')?.addEventListener('click', startSimDailyMission);
  $('#simNextCase')?.addEventListener('click', continueSimCaseFlow);
  $('#simReset')?.addEventListener('click', resetWorkSimulator);
  document.addEventListener('click', event => {
    const answer = event.target.closest('[data-sim-answer]');
    if (answer) evaluateSimAnswer(Number(answer.dataset.simAnswer));
    if (event.target.closest('#simEvaluateEmail')) evaluateSimEmail();
    if (event.target.closest('#simContinueDaily')) continueSimCaseFlow();
  });
  renderWorkSimulator();
  startSimCase('phone');
}

function chapterPartsForInteractive(chapterId) {
  const direct = PARTS_DATABASE.filter(p => p.relatedChapter === chapterId).slice(0, 4);
  if (direct.length) return direct;
  const fallback = PARTS_DATABASE.filter((_, index) => index % 50 === Number(chapterId) % 50).slice(0, 4);
  return fallback.length ? fallback : PARTS_DATABASE.slice(0, 4);
}
function simulatorModesForChapter(chapterId) {
  const n = Number(chapterId);
  if (n >= 26 && n <= 32) return ['parts', 'workshop', 'phone'];
  if ([12, 13, 14, 15, 17, 39, 41].includes(n)) return ['parts', 'phone', 'workshop'];
  if ([18, 21, 22, 23, 24, 25, 42, 43].includes(n)) return ['difficult', 'email', 'warranty'];
  if ([19, 20, 38, 40].includes(n)) return ['time', 'workshop', 'email'];
  if ([11, 16, 33, 34, 35, 36, 37, 44, 45, 46].includes(n)) return ['troubleshooting', 'workshop', 'daily'];
  return ['phone', 'parts', 'troubleshooting'];
}
function chapterWorkshopTip(chapterId) {
  const n = Number(chapterId);
  if (n >= 26 && n <= 32) return 'Sjekk alltid produsentens identifikasjonsfelt før du sammenligner delnummer. Samme motornavn kan ha flere varianter.';
  if ([12, 13, 14, 15, 17, 39, 41].includes(n)) return 'Be om bilde av typeplate og komponent. Avskrevne tegn, gamle nummer og posisjon på motoren er vanlige feilkilder.';
  if ([18, 19, 20, 21, 22, 23, 24, 25].includes(n)) return 'Når tempoet øker, skriv kortere, men ikke hopp over forbehold, neste steg og hvem som eier saken.';
  if ([33, 34, 35].includes(n)) return 'På eldre eller ombygde motorer er historikk og bilder like viktige som modellnavn. Marker alltid usikkerhet tydelig.';
  return 'Tenk system først og del etterpå: symptom, kontroll, årsak, delnummer og dokumentasjon må henge sammen.';
}
function chapterStepLabels(chapterId) {
  const n = Number(chapterId);
  if ([12, 13, 14, 15, 17, 39, 41].includes(n)) return ['Finn motor-ID', 'Bekreft variant', 'Sjekk delnummer', 'Dokumenter forbehold'];
  if ([18, 21, 22, 23, 24, 25, 42].includes(n)) return ['Lytt til kunden', 'Avklar fakta', 'Velg neste steg', 'Svar skriftlig'];
  if (n >= 26 && n <= 32) return ['Velg produsent', 'Finn korrekt ID-felt', 'Sjekk katalog', 'Verifiser supersession'];
  if ([11, 16, 33, 34, 35, 36, 37, 44, 45, 46].includes(n)) return ['Forstå systemet', 'Observer symptom', 'Kontroller komponent', 'Anbefal tiltak'];
  return ['Les situasjonen', 'Samle data', 'Kontroller kilde', 'Følg opp saken'];
}
function chapterExplanationCards(chapterId) {
  const n = Number(chapterId);
  if ([12, 13, 14, 15, 17, 39, 41].includes(n)) {
    return [
      ['Motoridentitet', 'Fabrikat, modell, serienummer, motornummer og variant må bekreftes før delvalg.'],
      ['Delnummer', 'Delnummer må kobles til riktig posisjon, antall, kitinnhold og eventuell supersession.'],
      ['Dokumentasjon', 'Bilder, katalogkilde og forbehold gjør at saken kan overtas av en kollega.']
    ];
  }
  if ([18, 21, 22, 23, 24, 25, 42, 43].includes(n)) {
    return [
      ['Kundedialog', 'Start med å roe saken, skille fakta fra antakelser og avtale neste oppdatering.'],
      ['Beslutningsgrunnlag', 'Et svar skal bygge på motor-ID, symptom, delbehov, lagerstatus og dokumenterte forbehold.'],
      ['Oppfølging', 'Lukk ikke saken før kunden vet hva som skjer videre og hva som eventuelt mangler.']
    ];
  }
  if (n >= 26 && n <= 32) {
    return [
      ['Produsentdata', 'Bruk produsentens egne ID-felt og katalogspråk før du sammenligner deler.'],
      ['Motorfamilie', 'Samme motorfamilie kan ha flere ratinger, applikasjoner og produksjonsendringer.'],
      ['Verifisering', 'Konkrete delnumre skal kontrolleres mot offisiell dokumentasjon før tilbud eller ordre.']
    ];
  }
  return [
    ['Systemforståelse', 'Se komponenten som en del av et system: luft, drivstoff, kjøling, smøring, elektrisk eller mekanisk.'],
    ['Feilsøking', 'Gå fra symptom til kontroll før du anbefaler en komponent eller et servicekit.'],
    ['Reservedelsvalg', 'Koble funksjon, posisjon, variant og produsentdata før du bekrefter delnummer.']
  ];
}
function chapterBeginnerMistakes(chapterId) {
  const n = Number(chapterId);
  if ([12, 13, 14, 15, 17, 39, 41].includes(n)) return ['Leser av feil tegn i serienummer.', 'Antar at modellnavn alene er nok.', 'Glemmer å sjekke om gammelt nummer er erstattet.'];
  if ([18, 19, 20, 21, 22, 23, 24, 25, 42, 43].includes(n)) return ['Lover levering før lager og frakt er kontrollert.', 'Svar blir for kort når kunden er stresset.', 'Dokumenterer ikke hva kunden faktisk ba om.'];
  if (n >= 26 && n <= 32) return ['Blander produsentenes ID-begreper.', 'Bruker generell motorfamilie i stedet for korrekt variant.', 'Overser at marine gear eller drev kan ha egen identitet.'];
  return ['Bytter del før enkel kontroll er gjort.', 'Blander symptom og årsak.', 'Glemmer miljø, driftstimer og siste service.'];
}
function chapterCustomerExample(chapter, parts) {
  const part = parts[0];
  return `Kunde spør etter ${part ? part.component : 'en reservedel'} til kapitteltemaet, men mangler komplett motor-ID. Riktig respons er å be om bilde av typeplate, serienummer/motornummer, symptom og bilde av aktuell komponent før delnummer bekreftes.`;
}
function chapterWorkshopExample(chapter, parts) {
  const part = parts[1] || parts[0];
  return `Mekaniker står med demontert område og trenger rask avklaring. Sjekk posisjon, antall, pakninger og om ${part ? part.component : 'delen'} inngår i enkeltkomponent, reparasjonssett eller servicekit.`;
}
function chapterInteractiveSummary(chapter) {
  return `Etter kapittel ${chapter.chapter} skal du kunne forklare hovedpoenget, stille riktige kontrollspørsmål, velge relevant simulatortrening og beskrive hva som må verifiseres før kunden får et bindende svar.`;
}
function renderInteractiveChapterBlock(chapter) {
  const quiz = quizById(chapter.chapter);
  const question = quiz?.questions?.[0];
  const parts = chapterPartsForInteractive(chapter.chapter);
  const steps = chapterStepLabels(chapter.chapter);
  const simModes = simulatorModesForChapter(chapter.chapter);
  const explanationCards = chapterExplanationCards(chapter.chapter);
  const beginnerMistakes = chapterBeginnerMistakes(chapter.chapter);
  return `<section class="chapter-interactive" data-interactive-chapter="${chapter.chapter}">
    <div class="interactive-head"><span class="kicker">Digital leksjon</span><h2>Øv mens du leser kapittel ${chapter.chapter}</h2><p>Bruk forklaringskort, motordeler, stegvis arbeidsflyt, miniquiz og simulatorlenker for å gjøre kapitlet praktisk.</p></div>
    <div class="explain-card-grid">${explanationCards.map((card, index) => `<button class="explain-card" data-explain-card="${index}" aria-expanded="false"><strong>${escapeHtml(card[0])}</strong><span>${escapeHtml(card[1])}</span></button>`).join('')}</div>
    <div class="interactive-chapter-grid">
      <article class="interactive-panel">
        <h3>Illustrasjoner og bilder av motordeler</h3>
        <div class="part-card-grid">${parts.map(part => `<div class="part-card"><div class="part-visual" aria-hidden="true"><span></span></div><strong>${escapeHtml(part.component)}</strong><em>${escapeHtml(part.system)} · ${escapeHtml(part.manufacturer)}</em><small>${escapeHtml(part.partNumber)}</small><p>Kontroller faktisk delnummer, variant og supersession mot produsentens dokumentasjon.</p></div>`).join('')}</div>
      </article>
      <article class="interactive-panel">
        <h3>Steg-for-steg</h3>
        <div class="step-animation">${steps.map((step, index) => `<div class="flow-step" style="--step:${index}"><span>${index + 1}</span><strong>${escapeHtml(step)}</strong></div>`).join('')}</div>
        <button class="secondary mini" data-run-steps>Spill av steg</button>
      </article>
      <article class="interactive-panel">
        <h3>Vanlige feil</h3>
        <ul>
          <li>Bekrefter del før motoridentitet er sikker.</li>
          <li>Bruker bilde som eneste grunnlag for bestilling.</li>
          <li>Glemmer å sjekke variant, side, antall eller kitinnhold.</li>
        </ul>
      </article>
      <article class="interactive-panel">
        <h3>Vanlige nybegynnerfeil</h3>
        <ul>${beginnerMistakes.map(item => `<li>${escapeHtml(item)}</li>`).join('')}</ul>
      </article>
      <article class="interactive-panel workshop-tip">
        <h3>Tips fra verkstedet</h3>
        <p>${escapeHtml(chapterWorkshopTip(chapter.chapter))}</p>
      </article>
      <article class="interactive-panel case-card">
        <h3>Praktisk kundeservice</h3>
        <p>${escapeHtml(chapterCustomerExample(chapter, parts))}</p>
      </article>
      <article class="interactive-panel case-card">
        <h3>Praktisk verksted</h3>
        <p>${escapeHtml(chapterWorkshopExample(chapter, parts))}</p>
      </article>
      <article class="interactive-panel">
        <h3>Miniquiz underveis</h3>
        ${question ? `<p>${escapeHtml(question.question)}</p><div class="mini-quiz">${question.choices.map((choice, index) => `<button data-mini-answer="${index}" data-correct="${index === question.answer ? 'true' : 'false'}">${escapeHtml(choice)}</button>`).join('')}</div><p class="mini-feedback muted hidden">${escapeHtml(question.explanation)}</p>` : '<p class="muted">Ingen quiz er koblet til dette kapitlet ennå.</p>'}
      </article>
      <article class="interactive-panel">
        <h3>Work Simulator</h3>
        <p>Tren kapitlet i realistiske saker.</p>
        <div class="action-row">${simModes.map(mode => `<button class="secondary" data-start-sim="${mode}">${escapeHtml(simModeLabel(mode))}</button>`).join('')}</div>
      </article>
    </div>
    <div class="interactive-summary"><strong>Kort oppsummering:</strong> ${escapeHtml(chapterInteractiveSummary(chapter))}</div>
  </section>`;
}
function initInteractiveChapters() {
  $$('.chapter-card').forEach(card => {
    if ($('.chapter-interactive', card)) return;
    const chapter = chapterById(card.dataset.chapter);
    const body = $('.chapter-body', card);
    if (!chapter || !body) return;
    const firstFigure = $('figure', body);
    if (firstFigure) firstFigure.insertAdjacentHTML('afterend', renderInteractiveChapterBlock(chapter));
    else body.insertAdjacentHTML('afterbegin', renderInteractiveChapterBlock(chapter));
  });
  document.addEventListener('click', event => {
    const stepBtn = event.target.closest('[data-run-steps]');
    if (stepBtn) {
      const block = stepBtn.closest('.chapter-interactive');
      block?.classList.remove('steps-running');
      void block?.offsetWidth;
      block?.classList.add('steps-running');
    }
    const explain = event.target.closest('[data-explain-card]');
    if (explain) {
      const expanded = explain.getAttribute('aria-expanded') === 'true';
      explain.setAttribute('aria-expanded', String(!expanded));
      explain.classList.toggle('open', !expanded);
    }
    const mini = event.target.closest('[data-mini-answer]');
    if (mini) {
      const panel = mini.closest('.interactive-panel');
      const ok = mini.dataset.correct === 'true';
      $$('[data-mini-answer]', panel).forEach(btn => {
        btn.disabled = true;
        btn.classList.toggle('correct', btn.dataset.correct === 'true');
        btn.classList.toggle('wrong', btn === mini && !ok);
      });
      const feedback = $('.mini-feedback', panel);
      if (feedback) {
        feedback.classList.remove('hidden');
        feedback.innerHTML = `<strong>${ok ? 'Riktig.' : 'Ikke helt.'}</strong> ${feedback.textContent}`;
      }
    }
    const sim = event.target.closest('[data-start-sim]');
    if (sim) {
      setView('work-simulator');
      startSimCase(sim.dataset.startSim);
      $('#view-work-simulator')?.scrollIntoView({ behavior: 'smooth', block: 'start' });
    }
  });
}

function init() {
  document.documentElement.dataset.theme = state.theme || 'light';
  bindCriticalActionRouter();
  bindEvents();
  renderDashboard();
  initQuiz();
  renderQuickRefs();
  renderSearch();
  initPhaseModules();
  initMarineTrainer();
  initWorkSimulator();
  initInteractiveChapters();
  updateProgressUI();
  openChapter(state.lastVisited || '01');
  setView('dashboard');
}
if (document.readyState === 'loading') {
  document.addEventListener('DOMContentLoaded', init, { once: true });
} else {
  init();
}
